/**
 * Decorator: Wrap component with WBCode/WBCodeFile display if active
 */
export function applyWbCode(self, h, finalRender) {
    // Gate on the resolved values (options.wbCode wins, then prop) so that
    // item.options.wbCode behaves identically to the :wbCode prop. The
    // *_ data fields are seeded from the prop only, so relying on them
    // misses the options-driven case.
    const wbCodeVN = self.resolvedWbCode == null ? null : self.vNodes.wbCode;
    const wbCodeFileVN = self.resolvedWbCodeFile == null ? null : self.vNodes.wbCodeFile;
    const wbDataViewerVN = self.resolvedWbDataViewer == null ? null : self.vNodes.wbDataViewer;

    if (wbCodeVN || wbCodeFileVN || wbDataViewerVN) {
        let renderWbcodeObj = {
            options: {},
            default_0: self.item_?.comp == "meta" ? null : {
                options: {
                    wrap: {
                        comp: 'VCard',
                        options: {
                            class: 'pa-3 my-3 ',
                            props: { outlined: true, shaped: true, rounded: true }
                        }
                    },
                    html: {
                        0: finalRender,
                        1: (h_) => wbCodeVN,
                        2: (h_) => wbCodeFileVN,
                        3: (h_) => wbDataViewerVN
                    }
                },
            },
        };

        return h("WBC", {
            key: `wbc-wrapper-${self.resolvedWbCode != null}-${self.resolvedWbCodeFile != null}-${self.resolvedWbDataViewer != null}-k${self.key_ || 0}`,
            props: {
                item: renderWbcodeObj,
                wbCode: null,
                wbCodeFile: null,
                wbDataViewer: null
            }
        });
    }
    return finalRender;
}
