/**
 * TeX Parser for Math support.
 */
export function parseTexFile(rawTex) {
    const blocks = [];
    const pushText = (txt) => { if (txt.trim()) blocks.push({ type: 'text', content: txt.trim() }); };
    const lines = rawTex.split('\n');
    let inDisplay = false; let displayBuffer = '';
    for (let i = 0; i < lines.length; i++) {
        let rawLine = lines[i]; const line = rawLine.replace(/%.*/, '').trimEnd();
        if (inDisplay) {
            const endIdx = line.indexOf('$$');
            if (endIdx !== -1) {
                displayBuffer += line.slice(0, endIdx);
                if (displayBuffer.trim()) blocks.push({ type: 'math', expression: displayBuffer.trim(), displayMode: true });
                inDisplay = false; displayBuffer = ''; processLine(line.slice(endIdx + 2), rawLine);
            } else displayBuffer += line + '\n';
            continue;
        }
        const startIdx = line.indexOf('$$');
        if (startIdx !== -1) {
            if (startIdx > 0) processLine(line.slice(0, startIdx), rawLine);
            const after = line.slice(startIdx + 2);
            const endIdx = after.indexOf('$$');
            if (endIdx !== -1) {
                const expr = after.slice(0, endIdx);
                if (expr.trim()) blocks.push({ type: 'math', expression: expr.trim(), displayMode: true });
                processLine(after.slice(endIdx + 2), rawLine);
            } else { inDisplay = true; displayBuffer = ''; }
            continue;
        }
        processLine(line, rawLine);
    }
    if (inDisplay && displayBuffer.trim()) blocks.push({ type: 'math', expression: displayBuffer.trim(), displayMode: true });
    function processLine(line, originalLine) {
        if (!line) return;
        const parts = []; let pos = 0;
        while (pos < line.length) {
            const dollarIdx = line.indexOf('$', pos);
            if (dollarIdx === -1) { parts.push({ content: line.slice(pos) }); break; }
            if (dollarIdx > pos) parts.push({ content: line.slice(pos, dollarIdx) });
            const rest = line.slice(dollarIdx + 1); const closeIdx = rest.indexOf('$');
            if (closeIdx === -1) { parts.push({ content: line.slice(dollarIdx) }); break; }
            const expr = rest.slice(0, closeIdx);
            if (expr.trim()) parts.push({ expression: expr.trim() });
            pos = dollarIdx + 1 + closeIdx + 1;
        }
        if (parts.length === 0) return;
        if (parts.length === 1) {
            const p = parts[0];
            if (p.content !== undefined) pushText(p.content);
            else blocks.push({ type: 'math', expression: p.expression, displayMode: false });
            return;
        }
        const mixed = { type: 'mixed', lineContent: [] }; let textBuffer = '';
        const flushBuffer = () => { if (textBuffer.trim()) { mixed.lineContent.push({ content: textBuffer.trim() }); textBuffer = ''; } };
        for (const p of parts) {
            if (p.content !== undefined) textBuffer += p.content + ' ';
            else { flushBuffer(); mixed.lineContent.push({ expression: p.expression }); }
        }
        flushBuffer(); blocks.push(mixed);
    }
    return blocks;
}

export function  replaceInObject(obj, replacements, targetDepth) {
    function traverse(current, depth) {
        const shouldReplace = targetDepth === undefined || depth === targetDepth;

        if (Array.isArray(current)) {
            for (let i = 0; i < current.length; i++) {
                if (shouldReplace && current[i] in replacements) {
                    current[i] = replacements[current[i]];
                } else {
                    traverse(current[i], depth + 1);
                }
            }
        } else if (current && typeof current === "object") {
            for (const key in current) {
                if (shouldReplace && current[key] in replacements) {
                    current[key] = replacements[current[key]];
                } else {
                    traverse(current[key], depth + 1);
                }
            }
        }
    }

    traverse(obj, 0);
    return obj;
}
