/**
 * Extract a sub-object from a deeply nested source using a shape map.
 * Each key in `subObj` is searched in `obj` (any depth); its value is either
 * a rename string (or null to keep the original key) or a nested shape map.
 * Nested maps can use `_parent_` to rename the wrapping key.
 *
 * @param {Object} obj - Source object (e.g. API response)
 * @param {Object} subObj - Shape map describing what to extract
 * @param {Object} [options] - { mode: 'first'|'merge'|'all'|<number> }
 * @returns {Object|Array|null}
 */
export function extractSubObject(obj, subObj, options = {}) {
    const { mode = 'first' } = options;

    if (!obj || typeof obj !== 'object' || !subObj || typeof subObj !== 'object') {
        return mode === 'all' ? [] : null;
    }

    function findAllParents(o, targetKey) {
        const results = [];
        if (!o || typeof o !== 'object') return results;
        if (targetKey in o) results.push(o);
        for (const key in o) {
            if (o[key] && typeof o[key] === 'object' && !Array.isArray(o[key])) {
                results.push(...findAllParents(o[key], targetKey));
            }
        }
        return results;
    }

    function findAllValues(o, targetKey) {
        const results = [];
        if (!o || typeof o !== 'object') return results;
        if (targetKey in o) results.push(o[targetKey]);
        for (const key in o) {
            if (o[key] && typeof o[key] === 'object' && !Array.isArray(o[key])) {
                results.push(...findAllValues(o[key], targetKey));
            }
        }
        return results;
    }

    function extractSingle(o, sub, m) {
        const result = {};
        Object.keys(sub).forEach(key => {
            if (key === '_parent_') return;
            const mapping = sub[key];
            if (mapping && typeof mapping === 'object') {
                const newParentKey = mapping._parent_ || key;
                const parents = findAllParents(o, key);
                if (parents.length > 0) {
                    const target = (m === 'merge') ? parents[parents.length - 1] : parents[0];
                    const nested = extractSubObject(target, mapping, { mode: m });
                    if (nested && Object.keys(nested).length > 0) result[newParentKey] = nested;
                }
            } else {
                const values = findAllValues(o, key);
                if (values.length > 0) {
                    const newKey = mapping || key;
                    result[newKey] = (m === 'merge') ? values[values.length - 1] : values[0];
                }
            }
        });
        return Object.keys(result).length > 0 ? result : null;
    }

    function extractNth(o, sub, n) {
        const result = {};
        Object.keys(sub).forEach(key => {
            if (key === '_parent_') return;
            const mapping = sub[key];
            if (mapping && typeof mapping === 'object') {
                const newParentKey = mapping._parent_ || key;
                const parents = findAllParents(o, key);
                if (parents.length > n) {
                    const nested = extractSubObject(parents[n], mapping, { mode: n });
                    if (nested && Object.keys(nested).length > 0) result[newParentKey] = nested;
                }
            } else {
                const values = findAllValues(o, key);
                if (values.length > n) {
                    const newKey = mapping || key;
                    result[newKey] = values[n];
                }
            }
        });
        return Object.keys(result).length > 0 ? result : null;
    }

    function extractAll(o, sub) {
        const topKeys = Object.keys(sub).filter(k => k !== '_parent_');
        if (topKeys.length === 0) return [];
        const parents = findAllParents(o, topKeys[0]);
        const results = [];
        parents.forEach((parent, index) => {
            const item = extractSubObject(parent, sub, { mode: index });
            if (item) results.push(item);
        });
        return results;
    }

    if (mode === 'all') return extractAll(obj, subObj);
    if (typeof mode === 'number' && mode >= 0) return extractNth(obj, subObj, mode);
    return extractSingle(obj, subObj, mode);
}

