// packages/wb-core/src/WBC.lifecycle.js
// Extracted lifecycle hooks from WBC.js

import { verifyAuthCookie, signAndSetAuthCookie, checkAuthCookieSync, clearAuthCookie } from './utils/auth.js';
import { maybeRegisterWbcItemRoute } from './utils/registerWbcRoute.js';

const __DEV__ = typeof __WBC_DEV__ !== 'undefined'
    ? __WBC_DEV__
    : (typeof process !== 'undefined' && process.env
        ? process.env.NODE_ENV !== 'production'
        : false);
const _isWBC_PRO = typeof __WBC_PRO__ !== 'undefined' ? __WBC_PRO__ : false;

export const wbLifecycleMixin = {
    beforeCreate() {
        this.vNodes = {};
        this.content = { input: {}, output: {} };
        this.$_finalRender = null;
    },

    created() {
        const isDev = (typeof __WBC_DEV__ !== 'undefined' && __WBC_DEV__ === true) || (this.$store?.getters?._wbcDev === true);

        if (_isWBC_PRO && !isDev) {
            // HMAC-SIGNED COOKIE VALIDATION — forgery-resistant
            // Sync structural check for fast path, full HMAC verification is async
            const existingAuth = checkAuthCookieSync();
            if (existingAuth) {
                this.$store.commit("setWbcProAuthorized", true);
                this.$store.commit("setWbcProDetails", existingAuth);
            } else if (this.$store && this.$store.state._wbcProValidationStarted['core'] === undefined) {
                this.$store.state._wbcProValidationStarted['core'] = true;

                // Async full HMAC verification (stricter than sync check)
                verifyAuthCookie().then(verifiedAuth => {
                    if (verifiedAuth) {
                        this.$store.commit("setWbcProAuthorized", true);
                        this.$store.commit("setWbcProDetails", { validated: true });
                    }
                }).catch(() => {});

                const key = this.$wbcUi2Options?.premiumKey;
                if (key === 'WBC_SIMULATE_PRO') {
                    // SIMULATION MODE: Immediate authorization for local testing AND first-party
                    // showcase builds (build:pro). The sentinel key means "simulate" in any non-free
                    // build — never hit the real LemonSqueezy endpoint for it (matches WBC1.js:5506).
                    console.warn("🛠️ WBC-UI2 PRO: Simulation Mode Active. Bypassing LemonSqueezy.");
                    const details = { premiumKey: 'WBC_SIMULATE_PRO', expiresAt: 'Never (Dev Mode)' };
                    signAndSetAuthCookie('valid').catch(() => {});
                    this.$store.commit("setWbcProAuthorized", true);
                    this.$store.commit("setWbcProDetails", details);
                } else if (key) {
                    fetch("https://api.lemonsqueezy.com/v1/licenses/validate", {
                        method: 'POST',
                        headers: { 'Accept': 'application/json', 'Content-Type': 'application/x-www-form-urlencoded' },
                        body: `license_key=${key}`
                    })
                        .then(res => res.json())
                        .then(data => {
                            if (data.valid === false) {
                                console.error("🚨 WBC-UI2 PRO: Invalid or Expired License Key. Premium features dynamically disabled.");
                                this.$store.commit("setWbcProAuthorized", false);
                                this.$store.commit("setWbcProDetails", null);
                                clearAuthCookie();
                            } else if (data.valid === true) {
                                const details = {
                                    premiumKey: key,
                                    expiresAt: data.meta?.expires_at || data.license_key?.expires_at,
                                    status: data.license_key?.status
                                };
                                signAndSetAuthCookie('valid').catch(() => {});
                                this.$store.commit("setWbcProAuthorized", true);
                                this.$store.commit("setWbcProDetails", details);
                            }
                        }).catch(() => {
                            // Fail Open during network errors
                        });
                } else {
                    console.error("🚨 WBC-UI2 PRO: No premiumKey provided in Vue.use(). Premium features dynamically disabled.");
                    this.$store.commit("setWbcProAuthorized", false);
                    this.$store.commit("setWbcProDetails", null);
                }
            }
        }

        // --- Slot text parsing ---
        if ((this.item === undefined || this.item === null) && this.$slots && this.$slots.default) {
            const slotText = this.$slots.default
                .map(v => (v && (v.text !== undefined ? v.text : (v.children && v.children.map(c => c.text).join('')))) || '')
                .join('').trim();
            if (slotText) {
                if (slotText.startsWith('~')) {
                    const body = slotText.slice(1).trim();
                    try { this.item_ = this.strToObj(body); } catch (e) { this.item_ = body; }
                } else {
                    this.item_ = slotText;
                }
            } else {
                this.item_ = this.item;
            }
        } else {
            this.item_ = this.item;
        }
        if (typeof this.item_ === 'string') this._originalItem = this.item_; // Preserve original path for wbCode

        if (typeof this.item === "string" && this.item.startsWith("~")) {
            this.item_ = { comp: "span", options: { html: this.item.slice(1) } };
        }

        // --- Wiki resolution ---
        this.wiki_ = this.wiki;
        if (this.wiki) {
            if (this.wiki.includes(",")) {
                this.item_ = this.wiki.split(",").map((e) => this.wbcWikiObj?.[e]);
            } else {
                let wiki = this.wbcWikiObj?.[this.wiki_];
                this.item_ = wiki || this.item_;
            }
        }

        if (!this.item_ || !this.item) {
            return null;
        }

        // --- Prop normalization ---
        this.wrap_ = this?.wrap
            ? {
                comp: this.wrap?.comp || this.wrap,
                options: this.wrap?.options || {},
            }
            : null;

        this.children_ = this.children;

        this.rColor = this?.item?.rColor || this.randomColor();

        this.nameEl = this.global_

        // --- Item initialization ---
        if (this.isPlainObject(this.item_)) {
            if (this.item_?.init0) {
                this.item_.init0(this.itemAccessibility);
            }

            this.nameEl = this?.item_?.options?.global || this.nameEl

            this.refName = "main_" + this.randomKey("", 3).toLowerCase();
            if (this.item_?.options && !this.item_?.options?.ref) {
                this.item_.options.ref = this.refName;
            }

            if (this.item_?.options) {
                this.internalValue = this?.item_?.options?.val;
            }

            this.dive = this.item_?.dive;

            if (typeof this.item_?.options?.props?.value == "boolean") {
                this.item_.options.props.value = this.item_.options.val;
            }

        } else {
            this.internalValue = this.item_;
        }

        this.nameEl = this.nameEl || this.randomKey("", 3).toLowerCase();

        // Expose itemAccessibility to window when user explicitly set a global name
        // (via the `global` prop or `item.options.global`)
        // SECURITY: Validate global name is a safe JS identifier to prevent XSS via
        // arbitrary key injection into window[] (e.g. global_="__proto__" or HTML event handlers)
        const _SAFE_IDENTIFIER_RE = /^[a-zA-Z_$][a-zA-Z0-9_$]*$/;
        if (this.global_ || this.item_?.options?.global) {
            const globalName = this.item_?.options?.global || this.global_;
            if (typeof globalName === 'string' && _SAFE_IDENTIFIER_RE.test(globalName)) {
                global[globalName] = this.itemAccessibility;
                // if (__DEV__) {
                    // console.warn(`[WBC-UI2 DEV] Global namespace assigned: window["${globalName}"] → itemAccessibility`);
                // }
            } else {
                console.error(`[WBC-UI2] Refused to assign global name "${globalName}" — not a valid JS identifier. ` +
                    `Expected pattern: /^[a-zA-Z_$][a-zA-Z0-9_$]*$/`);
            }
        }

        // DEV-only: additionally expose _vm and expose ALL named elements (even auto-generated)
        if (__DEV__) {
            if (this.nameEl && typeof this.nameEl === 'string' && _SAFE_IDENTIFIER_RE.test(this.nameEl)) {
                global[this.nameEl] = this.itemAccessibility;
                global[this.nameEl + "_vm"] = this;
                // console.warn(`[WBC-UI2 DEV] Global namespace assigned: window["${this.nameEl}"] + window["${this.nameEl}_vm"]`);
            }
        }

        if (this.dive) {
            this._preDiveItem = this.clone(this.item_);
            this.item_ = this.generalVal(
                this.item_,
                this.itemAccessibility,
                this.lang
            );
        }

        const rawOn = this?.item_?.options?.on || {};
        this.itemListeners = {};
        for (const [event, handler] of Object.entries(rawOn)) {
            if (typeof handler === "function") {
                this.itemListeners[event] = (...args) => handler(this.itemAccessibility, ...args);
            } else {
                this.itemListeners[event] = handler;
            }
        }

        // --- Watcher registration (PRO feature) ---
        const _authorized = this.$store?.getters?._wbcProAuthorized !== false;
        if (_isWBC_PRO && _authorized) {
            for (let aWatch of this.item_?.watch || []) {

                let theWatched;
                let aWatch_func = (newVal, oldVal) =>
                    aWatch[1](this.itemAccessibility, newVal, oldVal);
                if (aWatch[0] instanceof Function) {
                    theWatched = () => aWatch[0](this.itemAccessibility);
                } else if (typeof aWatch[0] == "string") {
                    theWatched = "itemAccessibility." + aWatch[0];
                } else if (Array.isArray(aWatch[0])) {
                    theWatched = () =>
                        aWatch[0].map((e) => {
                            if (e instanceof Function) {
                                return e(this.itemAccessibility);
                            } else if (typeof e == "string") {
                                // Safely evaluate nested properties instead of using new Function (code injection risk)
                                return e.split('.').reduce((o, i) => o?.[i], this.itemAccessibility);
                            }
                        });
                }
                this.$watch(theWatched, aWatch_func, ...aWatch.slice(2));
            }
        } else if (this.item_?.watch?.length) {
            console.warn("[WBC-UI2] Reactive watch[] orchestration requires a PRO license.");
        }
    },

    mounted() {
        if (this.isPlainObject(this.item_)) {
            if ((this.isWbcPro || __DEV__) && typeof this.item_?.init == "function") {
                this.item_.init(this.itemAccessibility);
            }

            if ((this.isWbcPro || __DEV__) && typeof this.item_?.logic == "function") {
                this.item_.logic(this.itemAccessibility);
            }
        }

        // Side effects for meta tags — apply on initial mount. Vue 2's updated() does NOT
        // fire on the first render, so a meta component that never re-renders would otherwise
        // never set the document title/favIcon. updated() (below) re-applies on later changes
        // (e.g. language switch).
        if (this.item_?.comp == "meta") {
            this.setMetaParams(this.item_, this.$store.state.lg);
        }

        // Self-registering routes: an object item that declares its own route coordinates
        // (options.name / options.path, + optional options.meta) becomes a permanent,
        // deep-linkable page — a route is registered (or reused) that re-renders this exact
        // item, then persisted via the host route sink so it survives a refresh. Browser-only
        // and fail-safe (maybeRegisterWbcItemRoute swallows everything); no-op without a router.
        if (typeof window !== "undefined" && this.isPlainObject(this.item_)) {
            maybeRegisterWbcItemRoute(this.$router, this.item_);
        }

        // Debug-select (Alt + middle-click → expose component as global `elm`) is a
        // DEVELOPMENT-ONLY affordance. Never wire it in free or pro builds.
        if (__DEV__) {
            this.$el.addEventListener("mousedown", this.handleMouseDown);
        }
    },

    updated() {
        if (this.item_ instanceof Object) {
            if (this.item_?.updater) {
                this.item_.updater(this.itemAccessibility);
            }
        }
        if (this.item_ instanceof Object) {
            if (this.item_?.options) {
                this.item_.options.isValid = this.internalValueIsValid;
            }
        }

        // Side effects for meta tags
        if (this.item_?.comp == "meta") {
            this.setMetaParams(this.item_, this.$store.state.lg);
        }

        // Sync global elm for debugger
        if (__DEV__) {
            if (this.select === true || this.isNonEmpty(this.alertObjs)) {
                global["elm"] = this.itemAccessibility;
            }
        }

        // Update content registry - MOVE TO RENDER for non-reactive sync
    },

    beforeDestroy() {
        // ADD-1 FIX: Remove mousedown listener to prevent memory leak
        if (this.$el) {
            this.$el.removeEventListener("mousedown", this.handleMouseDown);
        }
        document.removeEventListener("mousemove", this.doDrag);
        document.removeEventListener("mouseup", this.endDrag);
    }
};