/**
 * utils/formatting.js
 * Consolidated formatters for HTML, JSON, JS, and Strings
 */

/**
 * Capitalizes labels (snake_case to Title Case).
 */
export const capitalizeWords = (v) =>
    ` ${v}`
        .replace(/_/g, " ")
        .replace(/ ./g, (str) => str.toUpperCase())
        .trim();

/**
 * Basic capitalization of words.
 */
export const titleCase = function (aString) {
    if (typeof aString != "string") return aString;
    return aString
        .toLowerCase()
        .split(" ")
        .map(function (word) {
            return word.charAt(0).toUpperCase() + word.slice(1);
        })
        .join(" ");
};

/**
 * Advanced capitalization with intelligent exceptions.
 */
export const toTitleCase = function (aString) {
    if (typeof aString == "object" || !aString) {
        return "";
    }
    var i, j, str, lowers, uppers;
    str = aString.replace(/([^\W_]+[^\s-]*) */g, function (txt) {
        return txt.charAt(0).toUpperCase() + txt.substr(1).toLowerCase();
    });

    lowers = ["A", "An", "The", "And", "But", "Or", "For", "Nor", "As", "At", "By", "For", "From", "In", "Into", "Near", "Of", "On", "Onto", "To", "With"];
    for (i = 0, j = lowers.length; i < j; i++)
        str = str.replace(new RegExp("\\s" + lowers[i] + "\\s", "g"), function (txt) {
            return txt.toLowerCase();
        });

    uppers = ["Id", "Tv"];
    for (i = 0, j = uppers.length; i < j; i++)
        str = str.replace(new RegExp("\\b" + uppers[i] + "\\b", "g"), uppers[i].toUpperCase());

    return str;
};

/**
 * Format string by replacing underscores/hyphens and camelCase.
 */
export const formatToStr = function (inputString) {
    if (typeof inputString != "string") return inputString;
    return inputString
        .replace(/[_-]/g, " ")
        .replace(/([a-z])([A-Z])/g, "$1 $2")
        .replace(/([A-Z])([A-Z][a-z])/g, "$1 $2")
        .replace(/^./, (str) => str.toUpperCase())
        .replace(/\s+/g, " ");
};

/**
 * Format minutes to a human-readable duration string.
 */
export function minsToHours(minutes) {
    const hours = Math.floor(minutes / 60);
    const mins = minutes % 60;
    if (mins == 0) return `${hours}h`;
    return `${hours}h ${mins}m`;
}

/**
 * camelCase to kebab-case conversion.
 */
export const camelToKebab = function (str) {
    return str
        .replace(/^([A-Z])/, (match) => match.toLowerCase())
        .replace(/([a-z])([A-Z])/g, "$1-$2");
};

/**
 * Converts text to HTML paragraphs.
 */
export function textToParagraphs(text) {
    return text
        .split(/\r?\n/)
        .map(line => `<p>${line}</p>`)
        .join('');
}

/**
 * Converts text lines to HTML paragraphs.
 */
export function paragraphsFromText(text) {
    if (!text) return '';
    if (typeof text !== 'string') {
        try { text = JSON.stringify(text, null, 2); } catch (e) { text = String(text); }
    }
    return text
        .split(/\n+/)
        .map(line => line.trim())
        .filter(line => line.length)
        .map(line => `<p>${line}</p>`)
        .join("\n");
}

/**
 * Format any code string (HTML, JS, CSS, Vue, etc.) using Prettier
 */
export async function formatCode(code, language = null) {
    if (typeof code !== "string") return code;
    try {
        const prettier = await import("prettier/standalone");
        let parser = null;
        let plugins = [];
        if (language) {
            const map = {
                html: "html", htm: "html", vue: "vue",
                js: "babel", javascript: "babel", jsx: "babel",
                ts: "babel-ts", typescript: "babel-ts", tsx: "babel-ts",
                css: "css", scss: "scss", less: "less",
                json: "json", json5: "json5",
                markdown: "markdown", md: "markdown",
                graphql: "graphql", yaml: "yaml", yml: "yaml",
            };
            parser = map[language.toLowerCase()] || "html";
        }
        if (!parser) {
            const [html, babel, postcss, yaml] = await Promise.all([
                import("prettier/parser-html"),
                import("prettier/parser-babel"),
                import("prettier/parser-postcss"),
                import("prettier/parser-yaml").catch(() => null),
            ]);
            plugins = [html, babel, postcss];
            if (yaml) plugins.push(yaml);
            parser = prettier.getSupportInfo?.().languages
                .flatMap(lang => lang.parsers)
                .find(p => {
                    try {
                        prettier.format(code.slice(0, 1000), { parser: p, plugins });
                        return true;
                    } catch { return false; }
                }) || "html";
        }
        if (["html", "vue", "markdown"].includes(parser)) plugins = [await import("prettier/parser-html")];
        else if (parser.includes("babel")) plugins = [await import("prettier/parser-babel")];
        else if (["css", "scss", "less", "postcss"].includes(parser)) plugins = [await import("prettier/parser-postcss")];
        else if (["yaml", "yml"].includes(parser)) plugins = [await import("prettier/parser-yaml")];

        return prettier.format(code, {
            parser, plugins, tabWidth: 2, useTabs: false, printWidth: 100, semi: true,
            singleQuote: true, trailingComma: "es5", bracketSameLine: false,
            htmlWhitespaceSensitivity: "css", vueIndentScriptAndStyle: true,
        });
    } catch (err) {
        console.warn("[formatCode] Failed:", err.message);
        return code;
    }
}

/**
 * formatHtml – Beautify any HTML string
 */
export function formatHtml(str, { indentSize = 4, removeComments = true } = {}) {
    if (!str || typeof str !== 'string') return str;
    let html = str.trim();
    if (removeComments) {
        html = html.replace(/<!--[\s\S]*?-->/g, '').replace(/<!---->/g, '');
    }
    const indentStr = ' '.repeat(indentSize);
    let indentLevel = 0;
    let output = '';
    const parts = html.replace(/></g, '> <').split(/(<[^>]+>)/g).filter(Boolean);
    let previousWasTag = false;
    for (let part of parts) {
        const trimmed = part.trim();
        const isTag = /^</.test(trimmed);
        const isClosing = /^<\//.test(trimmed);
        const isSelfClosing = /\/>$/.test(trimmed);
        if (isTag) {
            if (isClosing && !isSelfClosing) indentLevel = Math.max(0, indentLevel - 1);
            output += '\n' + indentStr.repeat(indentLevel) + trimmed;
            previousWasTag = true;
            if (!isClosing && !isSelfClosing) indentLevel++;
        } else {
            const text = part.trim();
            if (text) {
                if (previousWasTag || output.endsWith('\n')) output += '\n' + indentStr.repeat(indentLevel);
                output += text;
                previousWasTag = false;
            }
        }
    }
    return output.trim() + '\n';
}

// Quick Aliases for HTML Formatting
export const beautifyHtml = (html) => formatHtml(html, { indentSize: 4 });
export const formatHtml2 = (html) => formatHtml(html, { indentSize: 2 });
export const pretty = formatHtml;

/**
 * formatJSON – Format a JSON string or object (Consolidated)
 */
export function formatJSON(input, { indent = 4 } = {}) {
    if (typeof input === 'string') {
        try { input = JSON.parse(input); } catch (e) { return input; }
    }
    return JSON.stringify(input, null, ' '.repeat(indent));
}

// Quick Aliases for JSON
export const json2 = (obj) => formatJSON(obj, { indent: 2 });
export const json4 = (obj) => formatJSON(obj, { indent: 4 });

/**
 * formatJS – The ultimate JS/JSON formatter (Consolidated)
 */
export function formatJS(input, { indent = 4 } = {}) {
    if (typeof input === 'string') {
        try {
            const parsed = JSON.parse(input);
            return JSON.stringify(parsed, null, indent);
        } catch (e) { return input; }
    }
    if (typeof input !== 'object' || input === null) {
        if (typeof input === 'function') return `function ${input.name || ''}() { ... }`;
        if (input === undefined) return 'undefined';
        return String(input);
    }
    const space = ' '.repeat(indent);
    return JSON.stringify(input, (key, value) => {
        if (typeof value === 'function') return `[Function${value.name ? ` ${value.name}` : ''}]`;
        if (value === undefined) return '[undefined]';
        if (typeof value === 'symbol' || typeof value === 'bigint') return value.toString() + (typeof value === 'bigint' ? 'n' : '');
        return value;
    }, space);
}

// Quick Aliases for JS
export const prettyJS = formatJS;
export const fmtJS = (obj, spaces = 4) => formatJS(obj, { indent: spaces });
export const fmtJS2 = (obj) => formatJS(obj, { indent: 2 });
export const fmtJS4 = (obj) => formatJS(obj, { indent: 4 });
export const logJS = (obj) => {
    if (typeof __WBC_DEV__ !== 'undefined' && __WBC_DEV__) {
        console.log(formatJS(obj, { indent: 4 }));
    }
};
