/*
 * Renders function nodes in WBC-UI2.
 * Extracted from WBC.js to break the monolith.
 */
export function renderFunction(context, el, h_) {
    let vNodeToReturn;
    // Skip internal lifecycle functions
    if (['tracker', 'init', 'update', 'init0'].includes(el?.name)) {
        vNodeToReturn = null;
    } else if (el?.length === 0) {
        vNodeToReturn = h_(el);
    } else if (el?.length === 1) {
        vNodeToReturn = el(h_);
    } else {
        vNodeToReturn = [
            h_("div", { class: "red--text" }, [
                "Function got more than 1 arguments (Expected 0 or 1 argument)",
                h_("div", {}, [el.toString()]),
            ]),
        ];
    }

    return vNodeToReturn;
}
