/**
 * renderers/menuHandler.js
 * Extracted from renderObject.js — handles the options.menu wrapper logic.
 * Supports both Vuetify activator-slot components (VMenu, VDialog, etc.)
 * and generic div-based menus.
 *
 * NOTE: This function mutates `self.menu` and `self.key_` as side effects.
 */

/**
 * Vuetify components that use the activator slot pattern.
 */
const VUETIFY_ACTIVATOR_COMPONENTS = [
    "VMenu",
    "VDialog",
    "VTooltip",
    "VHover",
    "VDropdown",
    "VDatePicker",
    "VExpansionPanel",
    "VBottomSheet",
];

/**
 * Wraps the rendered `main` VNode in a menu container if `options.menu` is defined.
 *
 * @param {Object} self - The WBC component instance
 * @param {Function} h_ - The createElement function
 * @param {VNode} main - The current main VNode to wrap
 * @param {Object} options - The component options (must contain `.menu`)
 * @returns {VNode} The menu-wrapped VNode
 */
export function applyMenuWrapper(self, h_, main, options) {
    if (!options?.menu) return main;

    self.menu = self.$refs[`menuHtml`]?.isActive || false;

    if (VUETIFY_ACTIVATOR_COMPONENTS.includes(options?.menu?.comp)) {
        return h_(
            options?.menu?.comp,
            {
                ref: "menuHtml",
                ...(self.menu?.active
                    ? options?.menu?.options
                    : options?.menu?.activeOptions),
                // Vuetify 2 requires the activator via a SCOPED slot that binds the slot's
                // `on` (and `attrs`) so the component controls open/close. A plain
                // `slot:"activator"` + manual toggle triggers "The activator slot must be
                // bound" and the menu won't open. We merge the activator's own listeners
                // (e.g. a custom `event`) UNDER Vuetify's `on` so opening still works.
                scopedSlots: {
                    activator: ({ on, attrs }) => {
                        const actOpts = (self.menu
                            ? options?.menu?.activeRootOptions
                            : options?.menu?.options) || {};
                        return h_(
                            options?.comp || "VCard",
                            {
                                ...actOpts,
                                key: self?.$refs?.[`menu`]?.isActive + self.menu,
                                attrs: { ...(actOpts.attrs || {}), ...attrs },
                                on: { ...(actOpts.on || {}), ...on },
                            },
                            [main]
                        );
                    },
                },
            },
            [
                h_("WBC", {
                    props: { item: options?.menu.content },
                }),
            ]
        );
    }

    // Generic (non-Vuetify) menu wrapper
    return h_(
        options?.menu?.comp || "div",
        {
            ...(!options?.menu?.active
                ? options?.menu?.options
                : options?.menu?.activeOptions),
        },
        [
            h_(
                options?.comp || "div",
                {
                    key: self?.$refs?.[`menu`]?.isActive + self.menu,
                    ...(options?.menu?.active
                        ? options?.menu?.activeRootOptions
                        : {}),
                    on: {
                        [options?.menu?.event || "click"]: () => {
                            options.menu.active = !options?.menu?.active;
                            self.key_ = (`${self.key_}` + "_").replace("___", "_");
                        },
                    },
                },
                [main]
            ),
            options?.menu?.active
                ? h_("WBC", { props: { item: options?.menu?.content } })
                : null,
        ]
    );
}
