<script>
import { sanitizeHtml } from "../utils";
import { resolveWbLinkTarget } from "../utils/registerWbcRoute";

export default {
  name: "WBLink",
  inheritAttrs: false,
  inject: {
    // Inherit an ancestor's "untrusted" verdict from the WBC/WBHtml subtree.
    // When set, route registration (name__ routes, file-ref routes, __defineRoute,
    // options.route self-registration) is blocked — untrusted content cannot create
    // persistent named vue-router routes. See registerWbcRoute.resolveWbLinkTarget.
    wbcUntrustedInjected: { default: false },
  },
  // Re-provide so nested WBLink instances (e.g. links inside rendered html)
  // also inherit the untrusted flag — the verdict cascades through the subtree.
  provide() {
    return { wbcUntrustedInjected: this.wbcUntrustedInjected === true };
  },
  props: {
    to: {},
    html: "",
    style_: {},
    attrs_: {},
    inactiveClass: String,
  },
  data() {
    return {
      // Resolved vue-router location when `to` points at a route (a `./`/`../`
      // file ref → auto-registered WBC route, an existing named route like
      // "AboutView", a route path like "/about", or a route-definition object).
      // null → render a plain <a> (external URL / in-page anchor / unknown).
      routeLoc: null,
    };
  },
  created() {
    this.resolveTarget();
  },
  watch: {
    // Links rarely change target, but stay correct if `to` is reassigned.
    to() {
      this.routeLoc = null;
      this.resolveTarget();
    },
  },
  methods: {
    // Register-off-render (spec §7): resolve `to` once into a route location or
    // an external link. Any failure (no router, bad def) is swallowed so the
    // link still renders as a plain <a>.
    resolveTarget() {
      try {
        const untrusted = this.wbcUntrustedInjected === true;
        const res = resolveWbLinkTarget(this.$router, this.to, this.$route?.path, untrusted);
        this.routeLoc = res.kind === "route" ? res.location : null;
      } catch (e) {
        console.error(`#WBLinkRouteError: ${e.message}`);
        this.routeLoc = null;
      }
    },
  },
  render(h) {
    // Route target → <RouterLink> (file refs, named routes, paths, defs, objects).
    if (this.routeLoc) {
      return h(
        "RouterLink",
        {
          ...this.attrs_,
          props: { to: this.routeLoc },
          style: { "text-decoration": "none", ...this.style_ },
        },
        [this.html]
      );
    }

    // Non-route: external URL / in-page anchor / plain text.
    const normalizedTo = typeof this.to === "string" ? this.to.trim() : this.to;
    let options = {
      props: {},
      style: { "text-decoration": "none", ...this.style_ },
      attrs: { href: normalizedTo, ...this.attrs_ },
    };
    // Trailing ">" opens the link in a new tab.
    if (typeof normalizedTo === "string" && normalizedTo[normalizedTo.length - 1] === ">") {
      options.attrs.href = normalizedTo.slice(0, -1);
      options.attrs.target = "_blank";
    }

    if (typeof this.html == "object") {
      // html is a VNode (e.g. a rendered file/icon) → wrap it directly.
      return h("a", options, [this?.html]);
    } else if (!this.to || !this.html) {
      return h("span", options, this?.html);
    }

    // html is a string → render as sanitized innerHTML inside the anchor.
    options = {
      props: {},
      style: { "text-decoration": "none", ...this.style_ },
      domProps: {
        innerHTML: sanitizeHtml([this?.html].join("")),
      },
      attrs: { href: normalizedTo, ...this.attrs_ },
    };
    return h("a", options);
  },
  components: {},
};
</script>
