// packages/wb-core/src/WBC.computed.js
// Extracted computed properties from WBC.js

import { createItemAccessibility } from './core/index.js';
import { LANG_MAP } from './constants.js';

export const wbComputedMixin = {
    computed: {
        computedKey() {
            // PERF-1 FIX: Use stable key generation to prevent excessive re-renders
            // Only depend on stable identity properties, not on reactive data that changes frequently
            
            // Use cached item_ reference to avoid triggering reactivity on the whole item object
            const item = this.item_;
            const options = item && typeof item === 'object' ? item.options : null;
            
            let baseKey = this.nameEl || "";
            
            // Only read the explicit key option if provided - don't access other reactive properties
            if (options) {
                const explicitKey = options.key;
                if (typeof explicitKey === 'string' || typeof explicitKey === 'number') {
                    baseKey = explicitKey;
                } else if (typeof explicitKey === 'object' && explicitKey !== null) {
                    baseKey = JSON.stringify(explicitKey).slice(0, 20); // Limit length for safety
                }
            }

            // Build key from stable identity properties only
            // Note: We deliberately avoid accessing this.item_ deeply or store state here
            // to prevent unnecessary re-computation when data changes
            const keyParts = [
                'key',
                this.nameEl || "",
                'n', baseKey,
                this.extKey || '',
                this.key_ || '',
                this.key || ""
            ];
            
            // Opt-in reactive key: only include content lengths if explicitly requested
            // This is opt-in to avoid breaking existing behavior
            if (options && options.reactiveKey) {
                const valLength = options.val?.length;
                const valueLength = options.props?.value?.length;
                if (valLength !== undefined) keyParts.push('v', valLength);
                if (valueLength !== undefined) keyParts.push('vv', valueLength);
            }
            
            return keyParts.join('-');
        },

        isWbcPro() {
            return this.$store?.getters?.isWbcPro || false;
        },
        wbcTier() {
            return this.$store?.getters?.userTier() || 'free';
        },
        itemMode: () => "itemMode",
        itemDisp: () => "itemDisp",
        itemProd: () => "itemProd",

        // CQ-4 FIX: Corrected typo from 'itemAccessebility' to 'itemAccessibility'
        itemAccessibility() {
            return createItemAccessibility(this, this.isWbcPro, this.wbcTier);
        },

        resolvedWbCode() {
            if (this.item_?.options?.wbCode != null) return this.item_?.options?.wbCode;
            if (this.wbCode != null) return this.wbCode;
            return null;
        },
        resolvedWbCodeFile() {
            if (this.item_?.options?.wbCodeFile != null) return this.item_?.options?.wbCodeFile;
            if (this.wbCodeFile != null) return this.wbCodeFile;
            return null;
        },
        resolvedWbDataViewer() {
            if (this.item_?.options?.wbDataViewer != null) return this.item_?.options?.wbDataViewer;
            if (this.wbDataViewer != null) return this.wbDataViewer;
            return null;
        },

        resolvedHide() {
            if (this.hide_ != null) return this.hide_;
            if (this.item_?.options?.hide != null) return this.item_.options.hide;
            if (this.hide != null) return this.hide;
            return null;
        },

        itemFileLanguage() {
            const src = typeof this.item_ === 'string' ? this.item_ : this._originalItem;
            if (typeof src !== 'string') return null;
            const langMap = LANG_MAP;
            const ext = src.split('.').pop()?.toLowerCase();
            return langMap[ext] || null;
        },

        lang() {
            return (
                this?.item_?.options?.lang ||
                this?.$store?.state?.lg ||
                this.getCookies()?.lg ||
                "en"
            );
        }
    }
};