// packages/wb-core/src/extended_install.js

import {
    WBHtml,
    WBLink,
} from './components';

import "./styles";

import Vuetify from "vuetify/lib";
import Vuex from "vuex";
import storeInst from "./store";

import { BootstrapVue, IconsPlugin } from "bootstrap-vue";
import VueCookiesImport from "vue-cookies";
const VueCookies = VueCookiesImport.default || VueCookiesImport;

import DayjsImport from "vue-dayjs";
const Dayjs = DayjsImport.default || DayjsImport;

import MarkdownIt from "markdown-it";
import markdownItAnchor from "markdown-it-anchor";
import markdownItCodeCopy from "markdown-it-code-copy";
import TurnDown from "turndown";

import JsonViewerImport from "vue-json-viewer";
const JsonViewer = JsonViewerImport.default || JsonViewerImport;

import * as methodsObj from "./utils";

// === FIX: ResizeObserver loop error ===
const debounce = (callback, delay) => {
    let tid;
    return (...args) => {
        clearTimeout(tid);
        tid = setTimeout(() => callback(...args), delay);
    };
};

if (typeof ResizeObserver !== "undefined") {
    const OriginalResizeObserver = ResizeObserver;
    window.ResizeObserver = class ResizeObserver {
        constructor(callback) {
            this.debouncedCallback = debounce(callback, 50);
            this.observer = new OriginalResizeObserver(this.debouncedCallback);
        }
        observe(target) {
            this.observer.observe(target);
        }
        unobserve(target) {
            this.observer.unobserve(target);
        }
        disconnect() {
            this.observer.disconnect();
        }
    };
}

// BUILD-3 FIX: Use singleton pattern to prevent duplicate Vuetify instances
// Import shared singleton getter from WBC.js to ensure single instance across modules
let _vuetifyInst = null;
export const getVuetifyInstance = () => {
    if (!_vuetifyInst) {
        _vuetifyInst = new Vuetify({
            theme: {
                dark: false,
                themes: {
                    light: {
                        primary: "#1976D2",
                        secondary: "#424242",
                        accent: "#82B1FF",
                        error: "#FF5252",
                        info: "#2196F3",
                        success: "#4CAF50",
                        warning: "#FFC107",
                    },
                },
            },
            icons: { iconfont: "mdi" },
            breakpoint: { mobileBreakpoint: "sm" },
        });
    }
    return _vuetifyInst;
};
const vuetifyInst = getVuetifyInstance();

const markdownItInst = new MarkdownIt({
    html: true,
    linkify: true,
    typographer: true,
    breaks: false,
})
    .use(markdownItAnchor, {
        permalink: markdownItAnchor.permalink.headerLink({ safariReaderFix: true }),
        slugify: (s) =>
            s
                .toLowerCase()
                .replace(/[^a-z0-9]+/g, "-")
                .replace(/(^-|-$)/g, ""),
    })
    .use(markdownItCodeCopy, {
        copyButtonText: "Copy",
        copiedButtonText: "Copied!",
        buttonClass: "pa-3",
        onSuccess: (evt) => {
            const clickedButton = evt.trigger;
            const iconElement = clickedButton.querySelector(".mdi") || clickedButton.querySelector("i");

            const originalIconClasses = iconElement ? iconElement.className : "";
            const originalIconColor = iconElement ? iconElement.style.color : "";

            if (iconElement) {
                iconElement.className = "mdi mdi-check";
                iconElement.textContent = "copied!";
                iconElement.style.color = "grey";

                setTimeout(() => {
                    iconElement.className = originalIconClasses;
                    iconElement.style.color = originalIconColor;
                    iconElement.textContent = "";
                }, 10000);
            }
        },
    });

export function install(app, options = {}) {
    if (!app) return;

    const plugins = [
        {
            name: "Vuex",
            property: "$store",
            fallback: Vuex,
            fallbackInstance: storeInst,
        },
        { name: "BootstrapVue", property: "$bootstrap", fallback: BootstrapVue },
        { name: "IconsPlugin", property: "$icons", fallback: IconsPlugin },
        { name: "JsonViewer", property: "$jsonViewer", fallback: JsonViewer },
        { name: "VueCookies", property: "$cookies", fallback: VueCookies },
        {
            name: "MarkdownIt",
            property: "$md",
            fallback: MarkdownIt,
            fallbackInstance: markdownItInst,
        },
        {
            name: "TurnDown",
            property: "$turndown",
            fallback: TurnDown,
            fallbackInstance: new TurnDown({
                headingStyle: "atx",
                bulletListMarker: "-",
                codeBlockStyle: "fenced",
                emDelimiter: "_",
            }),
        },
        {
            name: "Vuetify",
            property: "$vuetify",
            fallback: Vuetify,
            fallbackInstance: vuetifyInst,
        },
        ...(options?.plugins || []),
    ];

    plugins.forEach(
        ({ name, property, fallback, fallbackInstance, options: opts }) => {
            const pluginInstance =
                options?.plugins?.[name]?.plugin || fallbackInstance || fallback;
            const pluginOptions = options?.plugins?.[name]?.options || opts;

            if (pluginInstance) {
                if (property && app.prototype[property]) return;

                try {
                    if (typeof pluginInstance === 'function' && !pluginInstance.install && !pluginInstance.cid) {
                        return;
                    }

                    if (pluginOptions) app.use(pluginInstance, pluginOptions);
                    else app.use(pluginInstance);
                } catch (err) {
                    console.error(`[WBC Install] Failed to install ${name}:`, err);
                }
            }
        }
    );

    if (!app.prototype.$md) {
        app.prototype.$md = markdownItInst;
    }

    if (!app.prototype.$turndown) {
        const td = new TurnDown({
            headingStyle: "atx",
            bulletListMarker: "-",
            codeBlockStyle: "fenced",
            emDelimiter: "_",
        });
        app.prototype.$turndown = td;
        app.prototype.$turnDown = td;
    }

    app.mixin({
        beforeCreate() {
            app.use(Dayjs, {
                filters: { ago: "ago" },
                directives: { countdown: "countdown" },
            });

            app.component("WBHtml", WBHtml);
            app.component("WBLink", WBLink);
            app.component("JsonViewer", JsonViewer);

            Object.entries(options?.components || {}).forEach(([name, component]) => {
                app.component(name, component);
            });

            Object.assign(app.prototype, methodsObj);

            if (!app?.prototype?.$store) {
                app.prototype.$store = storeInst;
            }

            app.prototype.$wbcUi2Options = options;

            if (options?.lg && storeInst) {
                storeInst.commit("updateLang", options.lg);
                document.cookie = `lg=${encodeURIComponent(options.lg)}; path=/; max-age=31536000; SameSite=Lax`;
            }
        },
        methods: {
            renderVNodeToString(vnodeFn, cleanOpts = true, parentVm) {
                const vnode =
                    typeof vnodeFn === "function"
                        ? vnodeFn(this.$createElement)
                        : vnodeFn;

                const vm = new (app.extend())({
                    ...(parentVm ? { parent: parentVm } : {}),
                    render: (h) => vnode,
                }).$mount();

                let html = vm.$el.outerHTML;
                vm.$destroy();

                if (cleanOpts !== false) {
                    const opts =
                        cleanOpts === true
                            ? {
                                removeEmpty: ["span", "div"],
                                collapseWrappers: ["span", "div"],
                            }
                            : cleanOpts;
                    html = this.cleanVueHtml(html, opts);
                }

                return html;
            },

            mountVNode(vnodeFn, parentVm) {
                const vnode =
                    typeof vnodeFn === "function"
                        ? vnodeFn(this.$createElement)
                        : vnodeFn;
                const vm = new (app.extend())({
                    ...(parentVm ? { parent: parentVm } : {}),
                    render: (h) => vnode,
                }).$mount();

                return {
                    vm,
                    el: vm.$el,
                    get html() {
                        return this.cleanVueHtml(vm.$el.outerHTML);
                    },
                    destroy: () => vm.$destroy(),
                };
            },
        },
    });

}

const extendedInstall = {
    ...methodsObj,
    install,
    WBHtml,
    WBLink,
    JsonViewer,
    MarkdownIt,
    TurnDown,
    VueCookies,
    getVuetifyInstance,
};

export default extendedInstall;
