import { checkAuthCookieSync } from '../utils/auth.js';

export function enforceTierLimits(self, h) {
    if (isAuthorizedTier(self)) {
        return null;
    }

    const depth = self.getObjectDepth(self.item_);
    const isTooLongArr = Array.isArray(self.item_) && self.item_.length > 10;

    if (isTooLongArr || depth > 10) {
        let snippet = '';
        let fullSnippet = '';
        try {
            fullSnippet = JSON.stringify(self.item_);
            snippet = fullSnippet.substring(0, 40);
            if (snippet.length === 40) snippet += '...';
        } catch (e) {
            snippet = '[Complex Data]';
            fullSnippet = 'Cannot stringify: Object contains circular references (e.g. Vue components).';
        }

        self.$emit('tier-limit', {
            depth,
            length: Array.isArray(self.item_) ? self.item_.length : 0,
            item: self.item_,
            snippet
        });

        return h("VAlert", {
            ref: "rawHtml",
            props: { type: "warning", dense: true, outlined: true, dark: true },
            style: { margin: '10px' }
        }, [
            h("div", { class: "font-weight-bold" }, "WBC-UI Free Tier Limit (Max 10 items/depth)"),
            h("div", { attrs: { title: fullSnippet }, style: { fontSize: '0.85em', fontFamily: 'monospace', opacity: 0.8, margin: '4px 0' } }, `Blocked: ${snippet}`),
            h("div", { style: { fontSize: '0.9em', marginTop: '6px' } }, "Upgrade to Premium for unlimited data parsing.")
        ]);
    }

    return null;
}

export function isAuthorizedTier(self) {
    if (typeof __WBC_PRO__ !== 'undefined' && __WBC_PRO__ === true) {
        return true;
    }

    if (self.$store?.state?._wbcDev) {
        return true;
    }

    const cookieAuth = checkAuthCookieSync();
    if (cookieAuth && cookieAuth.validated) {
        return true;
    }

    return false;
}
