/**
 * Decorator: Wrap with VContainer if _focus is active
 */
export function applyFocusContainer(self, h, finalRender, _focus) {
    if (_focus) {
        return h(
            "VContainer",
            {
                ...(self.isPlainObject(_focus) ? _focus : _focus == true ? { style: { border: `1px solid black` } } : {}),
            },
            Array.isArray(finalRender) && finalRender.length > 0
                ? finalRender
                : [finalRender]
        );
    }
    return finalRender;
}
