import * as lzStringObj from "lz-string";

// Inherit the same definition as WBC.js
const __DEV__ = typeof __WBC_DEV__ !== 'undefined'
    ? __WBC_DEV__
    : (typeof process !== 'undefined' && process.env
        ? process.env.NODE_ENV !== 'production'
        : false);

/**
 * Creates the $wbc accessibility object for components.
 * This object is injected into the component and allows controlled access to internal state and methods.
 * 
 * @param {Object} self - The Vue component instance (this).
 * @param {boolean} isPro - Whether the user has a Premium license.
 * @param {string} tier - The user's current tier (e.g., 'Free', 'Pro').
 * @returns {Object} The accessibility object (acc).
 * 
 * @property {string} userTier - The current user tier.
 * @property {Object} license - Premium license details (Pro only).
 * @property {string} nameEl - The name of the component element.
 * @property {Object} props - Reference to self.$props.
 * @property {Object} data - Reactive getter/setter for self.item_.
 * @property {Function} toggleLoad - Toggles the loading state (load_).
 * @property {Function} toggleProtected - Toggles the protected state (protected_).
 * @property {Function} toggleFloat - Toggles the floating state (float_).
 * @property {Function} toggleClose - Toggles the close state (close_).
 * @property {Function} toggleFocus - Toggles the focus state (focus_).
 * @property {Function} toggleDrag - Toggles the drag state (drag_).
 * @property {Function} toggleHide - Toggles the hide state (hide_).
 * @property {Function} update - Triggers self.update(v).
 * @property {Function} compKey - Returns self.compKey.
 * @property {Object} lg - Language controls (get/set).
 * @property {Function} dayjs - Wrapper for dayjs (limited to ±14 days in Free tier).
 * @property {Function} emit - Alias for self.$emit.
 * @property {Object} storage - Component-specific storage (get/set).
 * @property {Object} cookies - Component-specific cookies (get/set).
 * 
 * @property {Object} root - The root child component (Pro only).
 * @property {Function} ref - Alias for self.$refs[v] (Pro only).
 * @property {Function} el - Alias for self.$el (Pro only).
 * @property {Function} routeParams - Returns self.$route.params (Pro only).
 * @property {Function} val - Alias for self.val(v) (Pro only).
 * @property {Function} isValid - Alias for self.internalValueIsValid (Pro only).
 * @property {Function} isValidFn - Alias for self.isValid(v) (Pro only).
 * @property {Function} set - Sets a data property (default: item_) (Pro only).
 * @property {Function} get - Gets a data property (default: item_) (Pro only).
 * @property {Object} refs - Alias for self.$refs (Pro only).
 * @property {Object} user - Current user from store — a VALUE getter, read as `that.user` (Pro only).
 * @property {boolean} loggedIn - Login status — a VALUE getter, read as `that.loggedIn` (Pro only).
 * @property {Function} content - Alias for self.contentRegistry (Pro only).
 * @property {Object} proto - Prototype of the component (Pro only).
 * @property {Object} vm - The raw component instance (Pro only).
 * @property {Object} markdown - Markdown rendering/parsing tools (Pro only).
 * @property {Object} store - The Vuex store (Pro only).
 * @property {Object} router - The Vue router (Pro only).
 * @property {Object} routes - Map of named routes (Pro only).
 * @property {Function} watch - Alias for self.$watch (Pro only).
 * @property {Function} queryData - Alias for self.queryData (Pro only).
 * @property {Object} aes - Encryption tools (Pro only).
 * @property {Object} lzStr - lz-string utility (Pro only).
 * @property {Object} validators - Validation rules (Pro only).
 * @property {Function} trigger - Calls a method on the instance by name (Pro only).
 * 
 * @property {any} focusOn - Getter/setter for focusOn_ (Pro only).
 * @property {boolean} protected - Getter/setter for protected_ (Pro only).
 * @property {boolean} focus - Getter/setter for focus_ (Pro only).
 * @property {boolean} load - Getter/setter for load_ (Pro only).
 * @property {boolean} float - Getter/setter for float_ (Pro only).
 * @property {boolean} drag - Getter/setter for drag_ (Pro only).
 * @property {boolean} close - Getter/setter for close_ (Pro only).
 * @property {boolean} hide - Getter/setter for hide_ (Pro only).
 * 
 * @property {boolean} wbCode - Toggles wbCode_ (Dev only).
 * @property {boolean} wbCodeFile - Toggles wbCodeFile_ (Dev only).
 */
export function createItemAccessibility(self, isPro, tier) {
    // --- FREE BUILD CAPABILITIES ---
    const acc = {
        userTier: tier,
        ...(isPro ? { license: self.$store?.getters?._wbcProDetails } : {}),
        nameEl: self.nameEl,
        props: self.$props,
        data: self.$data,

        toggleLoad: (v) => {
            if ((isPro || __DEV__) && v !== undefined) { self.load_ = v; }
            else { self.load_ = !self.load_; }
        },
        toggleProtected: (v) => {
            if ((isPro || __DEV__) && v !== undefined) { self.protected_ = v; }
            else { self.protected_ = !self.protected_; }
        },
        toggleFloat: (v) => {
            if ((isPro || __DEV__) && v !== undefined) { self.float_ = v; }
            else { self.float_ = !self.float_; }
        },
        toggleClose: (v) => {
            if ((isPro || __DEV__) && v !== undefined) { self.close_ = v; }
            else { self.close_ = !self.close_; }
        },
        toggleFocus: (v) => {
            if ((isPro || __DEV__) && v !== undefined) { self.focus_ = v; }
            else { self.focus_ = !self.focus_; }
        },
        toggleDrag: (v) => {
            if ((isPro || __DEV__) && v !== undefined) { self.drag_ = v; }
            else { self.drag_ = !self.drag_; }
        },
        toggleHide: (v) => {
            if ((isPro || __DEV__) && v !== undefined) { self.hide_ = v; }
            else { self.hide_ = !self.hide_; }
        },
        update: (v) => { self.update(v); },
        compKey: () => { return self.compKey; },

        lg: {
            lang: self.lang,
            get: () => self?.$store?.state?.lg || "en",
            set: (langage) => {
                self.$store.commit("updateLang", langage);
            },
        },
        dayjs: (() => {
            if (isPro || __DEV__) return (v) => { return self.dayjs(v); };
            return (v) => {
                const d = self.dayjs(v);
                const now = self.dayjs();
                const diff = Math.abs(now.diff(d, 'day'));
                if (diff > 14) {
                    console.warn('[WBC-UI2 Free] dayjs limited to ±14 days. Upgrade to Premium for full range.');
                    return null;
                }
                return d;
            };
        })(),
        emit: (e, v) => { self.$emit(e, v); },
        storage: {
            get: (v) => { return self.getStorage(v || self.nameEl); },
            set: (k, v) => { self.setStorage(k || self.nameEl, v); }
        },
        cookies: {
            get: (v) => { return self.getCookie(v); },
            set: (k, v) => { self.setCookie(k, v); }
        },
        key: self.key_,
    };

    Object.defineProperty(acc, 'data', {
        get() { return self.item_; },
        set(v) {
            if (typeof v === 'string' || typeof v === 'number' || typeof v === 'boolean') {
                self.item_ = null;
                self.$nextTick(() => {
                    self.item_ = v;
                });
            } else {
                self.item_ = v;
            }
        },
        enumerable: true,
        configurable: true,
    });

    if (isPro || __DEV__) {
        Object.assign(acc, {
            root: self.$root?.$children?.[0], 
            ref: (v) => { return self.$refs[v]; },
            el: (v) => { return self.$el; },
            routeParams: () => { return self.$route?.params || {}; },
            val: (v) => { return self.val(v); },
            isValid: () => { return self.internalValueIsValid; },
            isValidFn: (v) => { return self.isValid(v); },
            set: (val, key = "item_") => { self.$data[key] = val; },
            get: (key = "item_") => self.$data[key],
            refs: self?.$refs,
            content: () => { return self.contentRegistry; },
            proto: Object.getPrototypeOf(self), 
            vm: self, 
            emit: self.$emit, 
            markdown: { md2Html: (v) => self.$md.render(v), html2Md: (v) => self.$turnDown.turndown(v) },
            store: self.$store,
            router: self.$router,
            routes: self?.$router?.options?.routes ? Object.fromEntries(
                self?.$router?.options?.routes.map(route => [route.name, route])
            ) : null,
            watch: (p, cb, o) => { return self.$watch(p, cb, o); },
            queryData: self.queryData,
            aes: { enc: self.aesEnc, dec: self.aesDec },
            lzStr: lzStringObj,
            validators: { ...(self.validators || {}) },
            storage: localStorage, 
            cookies: { ...self.$cookies, state: self.getCookies || {} }, 
            dayjs: (v) => { return self.dayjs(v); }, 
            trigger: (name, ...args) => {
                if (typeof self[name] === 'function') return self[name](...args);
                console.warn(`[WBC-UI2 PRO] Method '${name}' not found on component instance.`);
            },
        });

        Object.defineProperty(acc, 'focusOn', { get() { return self.focusOn_; }, set(v) { self.focusOn_ = v; }, enumerable: true, configurable: true });
        Object.defineProperty(acc, 'protected', { get() { return self.protected_; }, set(v) { self.protected_ = v; }, enumerable: true, configurable: true });
        Object.defineProperty(acc, 'focus', { get() { return self.focus_; }, set(v) { self.focus_ = v; }, enumerable: true, configurable: true });
        Object.defineProperty(acc, 'load', { get() { return self.load_; }, set(v) { self.load_ = v; }, enumerable: true, configurable: true });
        Object.defineProperty(acc, 'float', { get() { return self.float_; }, set(v) { self.float_ = v; }, enumerable: true, configurable: true });
        Object.defineProperty(acc, 'drag', { get() { return self.drag_; }, set(v) { self.drag_ = v; }, enumerable: true, configurable: true });
        Object.defineProperty(acc, 'close', { get() { return self.close_; }, set(v) { self.close_ = v; }, enumerable: true, configurable: true });
        Object.defineProperty(acc, 'hide', { get() { return self.hide_; }, set(v) { self.hide_ = v; }, enumerable: true, configurable: true });

        // `user` / `loggedIn` are VALUE getters (not functions) — view-data reads them as
        // `that.loggedIn` (a boolean) e.g. `options.hide = that.loggedIn`. Exposing them as
        // functions made `that.loggedIn` truthy → everything hidden. Read `$store.state`
        // first (legacy source), then `getters`, matching the old in-app WBC.
        Object.defineProperty(acc, 'user', {
            get() { return self.$store?.state?.user ?? self.$store?.getters?.user ?? {}; },
            enumerable: true, configurable: true,
        });
        Object.defineProperty(acc, 'loggedIn', {
            get() { return self.$store?.state?.loggedIn ?? self.$store?.getters?.loggedIn ?? false; },
            enumerable: true, configurable: true,
        });
    }

    if (__DEV__) {
        Object.defineProperty(acc, 'wbCode', { get() { return self.wbCode_; }, set(v) { self.wbCode_ = v; }, enumerable: true, configurable: true });
        Object.defineProperty(acc, 'wbCodeFile', { get() { return self.wbCodeFile_; }, set(v) { self.wbCodeFile_ = v; }, enumerable: true, configurable: true });

        Object.assign(acc, {
            toggleWbCode: (v) => {
                if (v !== undefined) { self.wbCode_ = v; }
                else {
                    if (self.wbCode_ == null) self.wbCode_ = true;
                    else if (self.wbCode_ === true) self.wbCode_ = false;
                    else self.wbCode_ = null;
                }
                self.$forceUpdate();
            },
            toggleWbCodeFile: (v) => {
                if (v !== undefined) { self.wbCodeFile_ = v; }
                else {
                    if (self.wbCodeFile_ == null) self.wbCodeFile_ = true;
                    else if (self.wbCodeFile_ === true) self.wbCodeFile_ = false;
                    else self.wbCodeFile_ = null;
                }
                self.$forceUpdate();
            },
        });
    }

    return acc;
}
