// Dynamic WBC route registration + WBLink target resolution.
//
// Turns an internal *file reference* (a `to` string that starts with `./` or
// `../`) into a navigable, named WBC route on the fly, registers explicit
// route-definition objects, and resolves any WBLink `to` into the right kind of
// link (SPA route vs plain <a>). The route's component is WBC and its `item`
// prop is the original file string, so WBC's existing `./*.md` fetch-and-render
// pipeline (renderString → renderFile) does the actual loading — the route is
// just a stable address + name to navigate to (`this.$router.push({ name })`).
//
// Design notes (see Section-1 spec):
//   • Registration is idempotent: a given resolved path always maps to ONE
//     stable name via the module-level registry, so re-mounts never duplicate
//     routes or shift names. The incrementing suffix only fires when two
//     DIFFERENT paths collide on the same base name.
//   • The component is provided as a lazy `() => import('../WBC.js')` to break
//     the WBLink → WBC circular import at module-eval time.

import {
    compressToEncodedURIComponent,
    decompressFromEncodedURIComponent,
} from "lz-string";
// strToObj turns a payload string into the WBC item it denotes (object/array literal, or a
// plain string left as-is). Imported here for the `name__[path__]payload` link grammar — see
// parseNamedRouteString. No import cycle: security.js does not import this module.
import { strToObj } from "./security.js";

// resolvedPath -> finalName. Singleton across the app (and tolerant of HMR via
// the name-existence guard below).
const _pathToName = new Map();
// Names we have registered ourselves — belt-and-suspenders so collision
// detection works even on routers that expose neither getRoutes nor hasRoute.
const _usedNames = new Set();

// name -> serialized {item, meta, path} last emitted to the sink. `options.name` is the
// UNIQUE KEY of the persisted wbc:dynamicRoutes object: re-registering the same name with a
// DIFFERENT descriptor overrides the stored one; an identical re-mount is a no-op. This map
// lets us detect "changed vs. last emit" so we only persist real changes.
const _emittedItemRouteByName = new Map();

// Protocols / anchors that are always plain <a href> (never a SPA route).
const EXTERNAL_RE = /^(https?:|mailto:|tel:|sms:|ftp:|\/\/|www\.|#)/i;

// `routeName__[routePath__]<payload>`: a link target that NAMES a route AND carries the WBC
// item it should render. Instead of a plain external <a> / inert text, this registers a named,
// persisted WBC route whose `item` IS the payload (Case A-url — see registerWbcNamedUrlRoute):
//
//   routeName__<payload>             → name=routeName, path=/wbc/routeName   (default path)
//   routeName__routePath__<payload>  → name=routeName, path=routePath        (custom path)
//
// `<payload>` is the rendered item and may be:
//   • a URL string (`https://…img.jpg`) — kept verbatim; WBC renders it (img/video/iframe/…).
//   • an object / array literal — parsed via strToObj; becomes the route's `item` (the WBC
//     descriptor / array rendered as the page).
// A payload that is neither a URL nor a strToObj-parseable object/array is NOT this pattern
// (the match fails and resolution falls through), so arbitrary `a__b` strings aren't hijacked.
const NAMED_ROUTE_PREFIX_RE = /^([A-Za-z][\w-]*)__([\s\S]+)$/;

// WBHtml escapes markup-significant chars to HTML entities so they survive its `[[ … ]]` / `|`
// tokenizer (e.g. an author writes `\[`, `\]`, `\|` and `created()` turns them into
// `&lbrack;`, `&rbrack;`, `&vert;`). A *nested* array/object literal in a link payload trips
// that tokenizer — its adjacent `]]` / `[[` get read as block delimiters and the payload is
// truncated. Escaping the colliding brackets sidesteps it; we decode the entities back here, on
// the payload only, so `name__\[ 'a', \[ 'b' \] \]` round-trips to the real structure. (The
// space trick — writing `] ]` / `[ [` — needs no escaping and no decode; this just adds the
// explicit `\`-escape path, matching WBHtml's existing `\|` / `\{` convention.)
function decodeWbHtmlEscapes(s) {
    return s
        .replace(/&lbrack;/g, "[").replace(/&rbrack;/g, "]")
        .replace(/&lbrace;/g, "{").replace(/&rbrace;/g, "}")
        .replace(/&lpar;/g, "(").replace(/&rpar;/g, ")")
        .replace(/&lt;/g, "<").replace(/&gt;/g, ">")
        .replace(/&vert;/g, "|")
        .replace(/&#95;&#95;/g, "__");
}

// Turn a payload string into the WBC item it denotes: a URL stays a string; anything else is
// run through strToObj and accepted ONLY when it yields an object/array. Returns undefined when
// the string isn't a usable item (plain text, bad literal) → caller treats it as "no match".
function payloadToItem(raw) {
    if (typeof raw !== "string" || !raw) return undefined;
    const s = decodeWbHtmlEscapes(raw.trim());
    if (/^https?:\/\//.test(s)) return s;                       // URL → string item

    // Bracket-LESS comma list of literals → array — so `name__'<li>','a','b'` works with the
    // same brevity as the bracketed `name__['<li>','a','b']` (both render via renderArray).
    // strToObj alone can't: bare `'a','b','c'` evaluates through the JS comma operator to just
    // the LAST value. We wrap it in `[ … ]` and re-parse — but ONLY when it clearly begins with
    // a literal (quote or digit) and has a comma, so identifier text like `bar,baz` is never
    // coerced into `[undefined, …]`. Bracketed `[ … ]` and objects `{ … }` fall through to
    // strToObj below (a leading `{` would mis-wrap a single multi-key object, so it's excluded).
    if (/^['"\d]/.test(s) && s.includes(",")) {
        const arr = strToObj("[" + s + "]");
        if (Array.isArray(arr)) return arr;
    }

    const parsed = strToObj(s);
    return parsed && typeof parsed === "object" ? parsed : undefined;
}

// Parse `routeName__[routePath__]<payload>` → { name, path|null, item } or null (not a match).
// Disambiguating the optional middle path from a payload that itself contains `__` (objects
// often do): try the 3-part split at the FIRST `__` and accept it only when the right side is a
// valid payload; otherwise treat the whole remainder as the payload (2-part, default path).
function parseNamedRouteString(s) {
    const m = s.match(NAMED_ROUTE_PREFIX_RE);
    if (!m) return null;
    const name = m[1];
    const rest = m[2];

    const sep = rest.indexOf("__");
    if (sep > 0) {
        const item = payloadToItem(rest.slice(sep + 2));
        if (item !== undefined) return { name, path: rest.slice(0, sep), item };
    }

    const item = payloadToItem(rest);
    if (item !== undefined) return { name, path: null, item };

    return null;
}

/** True when `to` is a relative file reference (`./…` or `../…`). */
export function isWbcFileRef(to) {
    return typeof to === "string" && (to.startsWith("./") || to.startsWith("../"));
}

// Does a route with this name already exist?
//   • vue-router 4 → hasRoute()         (NOT available in vue-router 3.x)
//   • vue-router 3.5+ → getRoutes()     (this project: 3.6.x)
//   • otherwise → fall back to our own registered-name set
function routeNameExists(router, name) {
    if (typeof router.hasRoute === "function") return router.hasRoute(name);
    if (typeof router.getRoutes === "function") {
        return router.getRoutes().some((r) => r.name === name);
    }
    return _usedNames.has(name);
}

// The name of an already-registered route whose definition path is exactly `path`, or null.
// Lets us reuse a route rehydrated from persistence on a fresh session (when the in-memory
// _pathToName cache is empty) instead of minting a counter-suffixed duplicate.
function routeNameForPath(router, path) {
    if (typeof router.getRoutes === "function") {
        const hit = router.getRoutes().find((r) => r.path === path);
        return hit ? hit.name : null;
    }
    return null;
}

// Does a route match this path? Uses router.resolve() and checks `matched`.
function routePathMatches(router, path) {
    try {
        if (typeof router.resolve === "function") {
            const r = router.resolve(path);
            const route = (r && r.route) || r;
            return !!(route && route.matched && route.matched.length > 0);
        }
    } catch (e) { /* unmatched / resolve threw → treat as no match */ }
    return false;
}

/** POSIX-style path join that collapses `.` / `..` and clamps at root. */
function posixJoin(dir, rel) {
    const out = [];
    for (const seg of `${dir}/${rel}`.split("/")) {
        if (seg === "" || seg === ".") continue;
        if (seg === "..") out.pop();
        else out.push(seg);
    }
    return "/" + out.join("/");
}

/** "wbcVuetifyMd" -> "WbcVuetifyMd" (strip non-alphanumerics, PascalCase). */
function pascalCase(s) {
    return (s || "")
        .replace(/[^a-zA-Z0-9]+/g, " ")
        .trim()
        .split(/\s+/)
        .filter(Boolean)
        .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
        .join("");
}

/** Split off `?query` / `#hash` so they don't pollute the path/name. */
function splitSuffix(to) {
    const m = `${to}`.match(/^([^?#]*)([?#].*)?$/);
    return { core: m[1], suffix: m[2] || "" };
}

// Lazy WBC component factory — deferred import avoids the static cycle
// (WBC.js → WBLink.vue → registerWbcRoute.js → WBC.js).
const wbcComponent = () => import("../WBC.js").then((m) => m.default || m);

/**
 * Deep-clone a value into a JSON-safe shape: function values are flattened to cleaned
 * source strings so they survive serialization (URL transport AND localStorage), and WBC
 * re-parses those strings on render. Functions are NOT executed here — they stay inert text
 * until WBC evaluates them (under the dynamic route's `untrusted` AST sandbox for Case B).
 * Strings/numbers/etc. pass through untouched.
 */
function serializableClone(o) {
    const cleanFn = (fn) => fn.toString().replace(/\s+/g, " ").trim();
    if (typeof o === "function") return cleanFn(o);
    if (typeof o !== "object" || o === null) return o;
    const out = Array.isArray(o) ? [] : {};
    for (const [k, v] of Object.entries(o)) {
        out[k] =
            typeof v === "function"
                ? cleanFn(v)
                : v && typeof v === "object"
                ? serializableClone(v)
                : v;
    }
    return out;
}

/** Serialize a WBC descriptor to a JSON string for URL transport (Case B). */
function stringifyDescriptor(o) {
    return JSON.stringify(serializableClone(o));
}

// ── Persistence sink ─────────────────────────────────────────────────────────
// router.addRoute is session-only: a dynamically-registered named route vanishes on a
// full page refresh. To make these routes permanent, the host can register a sink here;
// the core calls it with a SERIALIZABLE `{ name, path, item }` each time it genuinely
// creates a named WBC route. The host (e.g. a Vuex store) persists those descriptors and
// rehydrates them into the router on the next boot. The core stays storage-agnostic — it
// neither imports Vuex nor knows the storage backend. No-op until a sink is set.
let _routeSink = null;

/**
 * Register a callback invoked with `{ name, path, item }` whenever a named WBC route is
 * newly created. Pass a falsy value to clear. Sink failures are swallowed so a broken host
 * persistence layer can never break navigation.
 */
export function setWbcRouteSink(fn) {
    _routeSink = typeof fn === "function" ? fn : null;
}

function emitRoute(name, path, item, meta, extra) {
    if (!_routeSink) return;
    try {
        const descriptor = { name, path, item: serializableClone(item) };
        if (meta !== undefined) descriptor.meta = serializableClone(meta);
        // Object-form `options.route` extra fields (guards: beforeEnter, alias, …)
        // travel to the host so they can be persisted + re-applied to the route index.
        if (extra && Object.keys(extra).length) descriptor.route = serializableClone(extra);
        _routeSink(descriptor);
    } catch (e) {
        console.error(`#WBCRouteSinkError: ${e.message}`);
    }
}

// Deprecation warnings fire once per key (per session) so a migrated codebase that
// still has a few legacy descriptors doesn't spam the console.
const _deprecationWarned = new Set();
function warnOnce(key, msg) {
    if (_deprecationWarned.has(key)) return;
    _deprecationWarned.add(key);
    if (typeof console !== "undefined") console.warn(msg);
}

/**
 * Resolve a WBC item descriptor's self-route coordinates from `options.route`
 * (the canonical key) with a DEPRECATED fallback to `options.name`/`options.path`.
 *
 *   options.route: 'Pricing'                       → { name:'Pricing' }
 *   options.route: { name, path, meta, ...guards }  → those fields, guards in `extra`
 *   options.name / options.path  (legacy)           → mapped + warn once
 *
 * `extra` carries any further vue-router route-record fields from the object form
 * (e.g. `beforeEnter`, `alias`, `redirect`) to spread onto the registered route and
 * emit to the persistence sink. Returns null when no route coordinates are declared.
 * @returns {{ name?:string, path?:string, meta?:any, extra:Object }|null}
 */
export function resolveItemRouteCoords(to) {
    const opt = to && typeof to === "object" && !Array.isArray(to) ? to.options : null;
    if (!opt) return null;

    const route = opt.route;
    if (route != null) {
        if (typeof route === "string") {
            return { name: route, path: null, meta: undefined, extra: {} };
        }
        if (typeof route === "object" && !Array.isArray(route)) {
            const { name, path, meta, ...extra } = route;
            if (!name && !path) return null;
            return { name, path: path || null, meta, extra };
        }
        return null;
    }

    // Deprecated path: options.name / options.path.
    if (opt.name || opt.path) {
        warnOnce(
            "options.name/path",
            "#WBCDeprecation: WBC item-route `options.name` / `options.path` are deprecated — " +
                "use `options.route` (a string, or `{ name, path, meta, …guards }`). " +
                "See _docs/wbc-links-routes."
        );
        return { name: opt.name, path: opt.path || null, meta: opt.meta, extra: {} };
    }
    return null;
}

/**
 * Register (or reuse) a named WBC route for a `./`/`../` file reference.
 * @returns {{name:string, path:string, suffix:string}}
 */
export function registerWbcRoute(router, to, currentRoutePath) {
    if (!router || typeof router.addRoute !== "function") {
        throw new Error(`#WBCRouteError: router unavailable for "${to}"`);
    }

    const { core, suffix } = splitSuffix(to);
    const currentDir = (currentRoutePath || "/").replace(/\/[^/]*$/, "") || "/";
    const joined = posixJoin(currentDir, core);
    const noExt = joined.replace(/\.[^/.]+$/, "");
    const path = "/wbc" + (noExt.startsWith("/") ? noExt : "/" + noExt);

    // Same path seen before → reuse the stable name, register nothing.
    if (_pathToName.has(path)) {
        return { name: _pathToName.get(path), path, suffix };
    }

    // Path already in the router but not in our cache (e.g. rehydrated from persistence on a
    // fresh session) → reuse its name; never mint a counter-suffixed duplicate for it.
    const existingName = routeNameForPath(router, path);
    if (existingName) {
        _pathToName.set(path, existingName);
        return { name: existingName, path, suffix };
    }

    const lastSeg = noExt.split("/").filter(Boolean).pop() || "page";
    const baseName = "WBC" + pascalCase(lastSeg);

    // Counter only on a genuine cross-path collision (different file, same base).
    let name = baseName;
    let i = 0;
    while (routeNameExists(router, name)) name = baseName + ++i;

    router.addRoute({
        path,
        name,
        component: wbcComponent,
        props: { item: to },
    });
    _pathToName.set(path, name);
    _usedNames.add(name);
    emitRoute(name, path, to);
    return { name, path, suffix };
}

/**
 * Register a verbatim route-definition object (Case C). The caller strips the
 * `__defineRoute` sentinel before passing `def`. A missing `name` is derived
 * from the path; an already-registered name is reused (no duplicate).
 * @returns {{name:string, path:string}}
 */
export function registerWbcRouteDef(router, def) {
    if (!router || typeof router.addRoute !== "function") {
        throw new Error(`#WBCRouteError: router unavailable`);
    }
    if (!def || typeof def !== "object" || typeof def.path !== "string") {
        throw new Error(`#WBCRouteError: invalid route definition (needs a string "path")`);
    }

    let name = def.name;
    if (!name) {
        const lastSeg = def.path.split("/").filter(Boolean).pop() || "page";
        name = "WBC" + pascalCase(lastSeg);
    }
    if (routeNameExists(router, name)) return { name, path: def.path };

    router.addRoute({ ...def, name });
    _usedNames.add(name);
    // Persist the WBC `item` so the route rehydrates as a WBC page on refresh. A Case C def
    // with a custom component is not fully serializable; only its item (if any) is carried.
    emitRoute(name, def.path, def.props?.item);
    return { name, path: def.path };
}

/**
 * Register (or reuse) a named WBC route for a descriptor that carries its own route
 * coordinates under `options.route` (Case A-object). Unlike a plain vue-router location,
 * the WHOLE descriptor is handed to WBC as the rendered `item`, so the page IS the
 * descriptor.
 *
 *   options.route: 'Pricing'                        → name 'Pricing', path '/wbc/Pricing'
 *   options.route: { name, path, meta, ...guards }   → those coordinates + guards
 *   options.name / options.path  (DEPRECATED)        → still honored, warns once
 *
 * The route name is `route.name` when present, else derived from `route.path`; `path`
 * defaults to `/wbc/<name>`; `route.meta` becomes route meta; any further route-record
 * fields (`beforeEnter`, `alias`, …) are spread onto the registered route AND emitted to
 * the persistence sink so they survive into the host's route index.
 * @returns {{name:string, path:string}}
 */
export function registerWbcItemRoute(router, to) {
    if (!router || typeof router.addRoute !== "function") {
        throw new Error(`#WBCRouteError: router unavailable`);
    }
    const coords = resolveItemRouteCoords(to);
    if (!coords) {
        throw new Error(`#WBCRouteError: item route needs options.route (a string, or { name, path })`);
    }
    const { meta: routeMeta, extra } = coords;
    let name = coords.name;
    const path = coords.path || (name ? "/wbc/" + name : null);
    if (!path) {
        throw new Error(`#WBCRouteError: item route needs options.route with a name or path`);
    }

    // Navigate by name. When only a path was given, derive a stable name from it so the
    // name-existence guard keeps registration idempotent across re-mounts.
    if (!name) {
        const lastSeg = path.split("/").filter(Boolean).pop() || "page";
        name = "WBC" + pascalCase(lastSeg);
    }

    // Detect whether this descriptor differs from what we last persisted for this name
    // (include the object-form `extra` route fields in the change signature).
    const serialized = JSON.stringify({
        item: serializableClone(to),
        meta: routeMeta ?? null,
        path,
        route: Object.keys(extra).length ? serializableClone(extra) : null,
    });
    const changed = _emittedItemRouteByName.get(name) !== serialized;

    // Add to the LIVE router only the first time this name appears. vue-router 3.6 can't
    // cleanly replace a named route (duplicate-name addRoute keeps the OLD record winning),
    // so an in-session content change updates the PERSISTED store instead — the source of
    // truth keyed by the route name. The live view picks the override up on the next router
    // build (refresh) or, for rehydrated routes, on the next navigation (their `item` is
    // resolved from the store by name — see the app's router rehydration).
    if (!routeNameExists(router, name)) {
        router.addRoute({
            ...extra, // object-form guards (beforeEnter, alias, …); the lines below win
            path,
            name,
            component: wbcComponent,
            props: { item: to },
            ...(routeMeta !== undefined ? { meta: routeMeta } : {}),
        });
        _usedNames.add(name);
    }

    // Persist on first sighting (this session) OR when the descriptor changed → the store
    // upserts by name (override). Identical re-mounts emit nothing.
    if (changed) {
        _emittedItemRouteByName.set(name, serialized);
        emitRoute(name, path, to, routeMeta, extra);
    }
    return { name, path };
}

/**
 * Register (or reuse) a named, persisted WBC route whose rendered `item` is the given payload,
 * parsed from a `routeName__[routePath__]<payload>` link target (Case A-url). `item` may be a
 * URL string (rendered as image/video/iframe/youtube/… via renderString) OR a WBC descriptor
 * object / array (rendered as the page). The route becomes an addressable in-app route — saved
 * through the sink (host store + localStorage) so it survives refresh — instead of a plain
 * external link / inert text. (Name kept `…UrlRoute` for API stability; the item is general.)
 *
 * `path` is optional: when omitted the route path defaults to `/wbc/<name>`; when supplied (the
 * middle `__routePath__` segment) it is used verbatim, with a leading `/` added if missing so a
 * bare `gallery/x` still yields a valid top-level vue-router path (`/gallery/x`). For route
 * `meta` / guards, use the object form `item.options.route`.
 *
 * Idempotent + override-aware, exactly like `registerWbcItemRoute`: the route name is the
 * unique persistence key. Re-registering the same name+path+item is a no-op; the same name with
 * a DIFFERENT path/item emits an override (the store upserts by name; the live route, which
 * vue-router 3.6 can't cleanly replace, picks the change up on the next router build / nav).
 * @param {string|object|Array} item - the WBC item the route renders (URL string, or descriptor).
 * @returns {{name:string, path:string}}
 */
export function registerWbcNamedUrlRoute(router, name, item, path) {
    if (!router || typeof router.addRoute !== "function") {
        throw new Error(`#WBCRouteError: router unavailable for named route "${name}"`);
    }
    const routePath = path
        ? (path.startsWith("/") ? path : "/" + path)
        : "/wbc/" + name;

    const serialized = JSON.stringify({ item: serializableClone(item), path: routePath });
    const changed = _emittedItemRouteByName.get(name) !== serialized;

    if (!routeNameExists(router, name)) {
        router.addRoute({
            path: routePath,
            name,
            component: wbcComponent,
            props: { item },
        });
        _usedNames.add(name);
    }
    if (changed) {
        _emittedItemRouteByName.set(name, serialized);
        emitRoute(name, routePath, item);
    }
    return { name, path: routePath };
}

/**
 * Guarded entry point for WBC.js (`mounted`): when a WBC renders an OBJECT item that declares
 * its own route coordinates (`options.route`, or the deprecated `options.name`/`options.path`),
 * register — or reuse — a permanent route that re-renders this exact item, making the rendered
 * block addressable and deep-linkable. The route is persisted through the sink (host store +
 * localStorage), so it survives refresh. No-op (returns null) for non-objects, items without
 * route coordinates, or when no router is available; never throws, so it can't break a mount.
 * @returns {{name:string, path:string}|null}
 */
export function maybeRegisterWbcItemRoute(router, item) {
    if (!item || typeof item !== "object" || Array.isArray(item)) return null;
    if (!resolveItemRouteCoords(item)) return null;
    if (!router || typeof router.addRoute !== "function") return null;
    try {
        return registerWbcItemRoute(router, item);
    } catch (e) {
        console.error(`#WBCItemRouteError: ${e.message}`);
        return null;
    }
}

/**
 * Register (once per router) the `/wbc/dynamic/routing/:item` route named `WBCDynamicRouting`
 * (Case B). It renders a WBC descriptor decompressed straight from the URL param, so any
 * object with no route coordinates can still be carried by a link. Idempotent via the
 * per-router name-existence guard (also covers HMR and hosts that pre-register the route).
 * @returns {{name:string, path:string}}
 */
export function registerWbcDynamicRoute(router) {
    const name = "WBCDynamicRouting";
    const path = "/wbc/dynamic/routing/:item";
    if (!router || typeof router.addRoute !== "function") {
        throw new Error(`#WBCRouteError: router unavailable`);
    }
    if (routeNameExists(router, name)) {
        return { name, path };
    }

    router.addRoute({
        path,
        name,
        component: wbcComponent,
        props: (route) => {
            // SECURITY: the descriptor is decompressed from an attacker-controllable URL
            // param. `untrusted: true` forces WBC's AST-sandbox evaluator for this render and
            // its whole subtree, so embedded handler strings can't run as `new Function`
            // closures (reflected XSS) — even though authored .md demos run full-power.
            let item = null;
            try {
                const raw = decompressFromEncodedURIComponent(route?.params?.item);
                try {
                    item = JSON.parse(raw);
                } catch (e) {
                    item = raw;
                }
            } catch (e) {
                item = null;
            }
            return { untrusted: true, item };
        },
    });
    _usedNames.add(name);
    return { name, path };
}

/**
 * Resolve a WBLink `to` into one of:
 *   { kind:'route', location }  — render <RouterLink :to="location">
 *   { kind:'external' }         — render plain <a href>
 *   { kind:'none' }             — nothing navigable
 *
 * String cases:  ./ or ../ file ref (Case A, auto-registered) · `name__[path__]<payload>`
 * (Case A-url, auto-registered to render the payload — a URL or a strToObj object/array — as
 * its item) · existing named route ("AboutView") · existing route path ("/about") ·
 * external/anchor (http(s)/mailto/tel/#/…) · anything else → external href.
 * Object cases:  __defineRoute definition (Case C) · descriptor with options.route
 * (Case A-object, auto-registered to render itself) · plain vue-router location · any
 * other descriptor → carried in the URL via LZ-string (Case B, WBCDynamicRouting).
 *
 * @param {object} router - vue-router instance
 * @param {*} to - link target (string or object)
 * @param {string} [currentRoutePath] - current route path for relative resolution
 * @param {boolean} [untrusted] - when true, skip ALL route registration cases (A, A-url,
 *   A-object, C) so untrusted content cannot register named vue-router routes. Existing
 *   routes, external links, and Case B (dynamic routing, which already hardcodes
 *   `untrusted: true`) are unaffected.
 */
export function resolveWbLinkTarget(router, to, currentRoutePath, untrusted) {
    // Untrusted gate: when the link originates from untrusted content, skip all route
    // REGISTRATION cases (A, A-url, A-object, C) so untrusted content cannot create
    // persistent named routes. Existing routes and external links are unaffected.
    const isUntrusted = untrusted === true;

    // Object: route definition (Case C) or a vue-router location passed as-is.
    if (to && typeof to === "object") {
        // Case C: explicit route-definition object — blocked when untrusted.
        if (to.__defineRoute) {
            if (isUntrusted) return { kind: "external" };
            const { __defineRoute, ...def } = to;
            const res = registerWbcRouteDef(router, def);
            return { kind: "route", location: { name: res.name } };
        }

        // Case A-object: descriptor that names its own route via options.route (or the
        // deprecated options.name/options.path). Register (or reuse) a named WBC route
        // whose `item` IS the whole descriptor. Blocked when untrusted.
        if (to.options && resolveItemRouteCoords(to)) {
            if (isUntrusted) return { kind: "external" };
            const res = registerWbcItemRoute(router, to);
            return { kind: "route", location: { name: res.name } };
        }

        // Treated case (summary): a plain vue-router location ({ name } / { path }).
        if (to.name || to.path) {
            return { kind: "route", location: to };
        }

        // Case B: any other object has no route coordinates — carry the whole descriptor in
        // the URL (LZ-string) and render it through the shared WBCDynamicRouting route.
        registerWbcDynamicRoute(router);
        return {
            kind: "route",
            location: {
                name: "WBCDynamicRouting",
                params: {
                    item: compressToEncodedURIComponent(stringifyDescriptor(to)),
                },
            },
        };
    }

    if (typeof to !== "string") return { kind: "none" };
    const s = to.trim();
    if (!s) return { kind: "none" };

    // `name__[path__]<payload>` → register a persisted WBC route that renders the payload as its
    // item, then navigate by name (Case A-url). `<payload>` is a URL string OR a strToObj-parsed
    // object/array; the optional middle segment sets a custom path (default `/wbc/<name>`). Must
    // precede the external test, which would otherwise need the whole string as an href. (Like
    // the `./` file-ref case, this throws without a router; WBLink catches → plain <a>.)
    // Blocked when untrusted — untrusted content cannot create persistent named routes.
    const named = parseNamedRouteString(s);
    if (named) {
        if (isUntrusted) return { kind: "external" };
        const res = registerWbcNamedUrlRoute(router, named.name, named.item, named.path);
        return { kind: "route", location: { name: res.name } };
    }

    // Explicit external / in-page anchor → plain <a>.
    if (EXTERNAL_RE.test(s)) return { kind: "external" };

    // Relative file ref → register + navigate by name (Case A). Blocked when untrusted.
    if (isWbcFileRef(s)) {
        if (isUntrusted) return { kind: "external" };
        const res = registerWbcRoute(router, s, currentRoutePath);
        const location = { name: res.name };
        if (res.suffix && res.suffix.startsWith("#")) location.hash = res.suffix;
        else if (res.suffix && res.suffix.startsWith("?")) {
            location.query = Object.fromEntries(new URLSearchParams(res.suffix.slice(1)));
        }
        return { kind: "route", location };
    }

    // Existing named route, e.g. "AboutView".
    if (router && routeNameExists(router, s)) {
        return { kind: "route", location: { name: s } };
    }

    // Existing route path, e.g. "/about".
    if (s.startsWith("/") && router && routePathMatches(router, s)) {
        return { kind: "route", location: { path: s } };
    }

    // Anything else (bare relative href, unknown word) → external href.
    return { kind: "external" };
}
